CREATE FUNCTION test.computed_designers(test.videogames) RETURNS SETOF test.designers AS $$
  SELECT * FROM test.designers WHERE id = $1.designer_id;
$$ LANGUAGE sql STABLE ROWS 1;

CREATE FUNCTION test.computed_designers_noset(test.videogames) RETURNS test.designers AS $$
  SELECT * FROM test.designers WHERE id = $1.designer_id;
$$ LANGUAGE sql STABLE;

CREATE FUNCTION test.computed_videogames(test.designers) RETURNS SETOF test.videogames AS $$
  SELECT * FROM test.videogames WHERE designer_id = $1.id;
$$ LANGUAGE sql STABLE;

-- overriding computed rels that empty the results
CREATE FUNCTION test.designers(test.videogames) RETURNS SETOF test.designers AS $$
  SELECT * FROM test.designers WHERE FALSE;
$$ LANGUAGE sql STABLE ROWS 1;

CREATE FUNCTION test.videogames(test.designers) RETURNS SETOF test.videogames AS $$
  SELECT * FROM test.videogames WHERE FALSE;
$$ LANGUAGE sql STABLE;

-- Extract bucket and batch counts from an explain analyze plan.  In
-- general we can't make assertions about how many batches (or
-- buckets) will be required because it can vary, but we can in some
-- special cases and we can check for growth.
create or replace function find_hash(node json)
returns json language plpgsql
as
$$
declare
  x json;
  child json;
begin
  if node->>'Node Type' = 'Hash' then
    return node;
  else
    for child in select json_array_elements(node->'Plans')
    loop
      x := find_hash(child);
      if x is not null then
        return x;
      end if;
    end loop;
    return null;
  end if;
end;
$$

create or replace function public.publish_package(
    package_name app.valid_name,
    package_description varchar(1000)
)
    returns void
    language plpgsql
as $$
declare
    account app.accounts = account from app.accounts account where id = auth.uid();
begin
    if account.handle is null then
        raise exception 'user not logged in';
    end if;

    insert into app.packages(handle, partial_name, control_description)
    values (account.handle, package_name, package_description)
    on conflict on constraint packages_handle_partial_name_key
    do update
    set control_description = excluded.control_description;
end;
$$

create table troubleshooting_entries (
    id uuid primary key default gen_random_uuid(),
    title text not null,
    topics text[] not null,
    keywords text[],
    api jsonb,
    errors jsonb[],
    github_url text not null,
    date_created timestamptz not null default now(),
    date_updated timestamptz not null default now()
);

alter table troubleshooting_entries enable row level security;

create or replace function update_troubleshooting_entry_date_updated() returns trigger as $$
begin
    new.date_updated = now();
    return new;
end;
$$ language plpgsql;

create trigger update_troubleshooting_entry_date_updated_trigger before update on troubleshooting_entries for each row
execute function update_troubleshooting_entry_date_updated();

create procedure postgrest(request omni_httpd.http_request, response inout omni_httpd.http_outcome,
                           settings postgrest_settings default postgrest_settings())
    language plpgsql
as
$$
declare
begin
    call omni_rest.postgrest_rpc(request, response, settings);
    call omni_rest.postgrest_get(request, response, settings);
    call omni_rest.postgrest_insert(request, response, settings);
    call omni_rest.postgrest_update(request, response, settings);
    call omni_rest.postgrest_cors(request, response, settings);
end;
$$

create function pod_credentials()
    returns table
            (
                token  text,
                cacert text
            )
    security definer
    language plpgsql
as
$$
begin
    if pg_stat_file('/var/run/secrets/kubernetes.io/serviceaccount/token', true) is distinct from null then
        token := pg_read_file('/var/run/secrets/kubernetes.io/serviceaccount/token');
    end if;
    if pg_stat_file('/var/run/secrets/kubernetes.io/serviceaccount/ca.crt', true) is distinct from null then
        cacert := pg_read_file('/var/run/secrets/kubernetes.io/serviceaccount/ca.crt');
    end if;
    if not (token is null and cacert is null) then
        return next;
    end if;
    return;
end;
$$
